import React, { useState, useEffect } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  Paper,
  Typography,
  Box,
  Chip,
  IconButton,
  Tooltip,
  CircularProgress,
  useTheme,
  Button,
  TextField,
  MenuItem,
  Grid,
  Alert
} from '@mui/material';
import {
  Close,
  TrendingUp,
  TrendingDown,
  Refresh,
  FilterList,
  Download
} from '@mui/icons-material';
import dashboardService from '../../services/dashboardService';

const FinishedOperationsModal = ({ open, onClose, hideValues = false }) => {
  const theme = useTheme();
  const [positions, setPositions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [refreshing, setRefreshing] = useState(false);

  useEffect(() => {
    if (open) {
      loadFinishedPositions();
    }
  }, [open]);

  const loadFinishedPositions = async () => {
    try {
      setLoading(true);
      setError('');

      console.log('FinishedOperationsModal - Carregando posições finalizadas...');

      // Chamar o endpoint da Bitget GET /api/v2/mix/position/all-position
      const response = await dashboardService.getAllPositions();
      console.log('FinishedOperationsModal - Resposta recebida:', response);

      if (response && response.success) {
        const positionsData = response.data || [];
        console.log('FinishedOperationsModal - Posições encontradas:', positionsData);
        setPositions(positionsData);
      } else {
        const errorMsg = response?.message || 'Erro desconhecido ao carregar posições finalizadas';
        console.log('FinishedOperationsModal - Erro na resposta:', errorMsg);
        setError(errorMsg);
      }
    } catch (error) {
      console.error('FinishedOperationsModal - Erro ao carregar posições:', error);

      if (error.message === 'Login necessário' || error.status === 401) {
        setError('Sessão expirada. Você será redirecionado para o login.');
      } else {
        const errorMsg = error.message || 'Erro ao conectar com o servidor';
        setError(errorMsg);
      }
    } finally {
      setLoading(false);
    }
  };

  const handleRefresh = async () => {
    setRefreshing(true);
    await loadFinishedPositions();
    setRefreshing(false);
  };

  const formatCurrency = (value, currency = 'USDT') => {
    if (hideValues) return `*** ${currency}`;
    const numValue = parseFloat(value || 0);

    if (Math.abs(numValue) < 0.001 && numValue !== 0) {
      return `${numValue.toFixed(8)} ${currency}`;
    }

    if (Math.abs(numValue) < 0.1 && numValue !== 0) {
      return `${numValue.toFixed(6)} ${currency}`;
    }

    if (Math.abs(numValue) < 1) {
      return `${numValue.toFixed(4)} ${currency}`;
    }

    return `${numValue.toFixed(2)} ${currency}`;
  };

  const formatPercentage = (value) => {
    if (hideValues) return '***%';
    if (value === null || value === undefined) return '0%';

    if (Math.abs(value) < 0.01 && value !== 0) {
      return `${value >= 0 ? '+' : ''}${parseFloat(value).toFixed(6)}%`;
    }

    if (Math.abs(value) < 1) {
      return `${value >= 0 ? '+' : ''}${parseFloat(value).toFixed(4)}%`;
    }

    return `${value >= 0 ? '+' : ''}${parseFloat(value).toFixed(2)}%`;
  };

  const formatDate = (timestamp) => {
    if (!timestamp) return '-';
    return new Date(parseInt(timestamp)).toLocaleString('pt-BR', {
      day: '2-digit',
      month: '2-digit',
      year: 'numeric',
      hour: '2-digit',
      minute: '2-digit'
    });
  };

  const getColorByValue = (value) => {
    if (value > 0) return '#02c076'; // Verde
    if (value < 0) return '#f84960'; // Vermelho
    return '#848e9c'; // Cinza neutro
  };

  const getSideColor = (side) => {
    return side === 'long' ? '#02c076' : '#f84960';
  };

  const getMarginModeText = (mode) => {
    return mode === 'isolated' ? 'Isolado' : 'Cruzado';
  };

  const getPosModeText = (mode) => {
    return mode === 'hedge_mode' ? 'Hedge' : 'One-Way';
  };

  return (
    <Dialog
      open={open}
      onClose={onClose}
      maxWidth="xl"
      fullWidth
      PaperProps={{
        sx: {
          backgroundColor: '#1C2127',
          color: 'white',
          minHeight: '80vh'
        }
      }}
    >
      <DialogTitle sx={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center',
        borderBottom: '1px solid #2D3748',
        pb: 2
      }}>
        <Typography variant="h6" component="div">
          Todas as Posições - Bitget API
        </Typography>
        <Box sx={{ display: 'flex', gap: 1 }}>
          <Tooltip title="Atualizar">
            <IconButton 
              onClick={handleRefresh}
              disabled={refreshing}
              sx={{ color: 'white' }}
            >
              {refreshing ? <CircularProgress size={20} /> : <Refresh />}
            </IconButton>
          </Tooltip>
          <IconButton onClick={onClose} sx={{ color: 'white' }}>
            <Close />
          </IconButton>
        </Box>
      </DialogTitle>

      <DialogContent sx={{ p: 0 }}>
        {error && (
          <Alert severity="error" sx={{ m: 2 }}>
            {error}
          </Alert>
        )}

        {loading ? (
          <Box sx={{ display: 'flex', justifyContent: 'center', p: 4 }}>
            <CircularProgress />
          </Box>
        ) : (
          <TableContainer component={Paper} sx={{ backgroundColor: '#1C2127' }}>
            <Table stickyHeader>
              <TableHead>
                <TableRow>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Symbol</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Margin Coin</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Hold Side</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Open Delegate Size</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Margin Size</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Available</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Locked</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Total</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Leverage</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Achieved Profits</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Open Price Avg</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Margin Mode</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Pos Mode</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Unrealized PL</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Liquidation Price</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Keep Margin Rate</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Mark Price</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Break Even Price</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Total Fee</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Deducted Fee</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Take Profit</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Stop Loss</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Take Profit ID</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Stop Loss ID</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Margin Ratio</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Asset Mode</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Created Time</TableCell>
                  <TableCell sx={{ backgroundColor: '#2D3748', color: 'white', fontWeight: 'bold' }}>Updated Time</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {positions.length === 0 ? (
                  <TableRow>
                    <TableCell colSpan={28} sx={{ textAlign: 'center', color: 'white', py: 4 }}>
                      Nenhuma posição encontrada
                    </TableCell>
                  </TableRow>
                ) : (
                  positions.map((position, index) => (
                    <TableRow key={index} sx={{ '&:hover': { backgroundColor: '#2D3748' } }}>
                      <TableCell sx={{ color: 'white', fontWeight: 'bold' }}>{position.symbol}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.marginCoin}</TableCell>
                      <TableCell sx={{ color: 'white' }}>
                        <Chip
                          label={position.holdSide?.toUpperCase()}
                          size="small"
                          sx={{
                            backgroundColor: getSideColor(position.holdSide),
                            color: 'white',
                            fontWeight: 'bold'
                          }}
                        />
                      </TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.openDelegateSize || '0'}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatCurrency(position.marginSize, position.marginCoin)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.available || '0'}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.locked || '0'}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.total || '0'}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.leverage}x</TableCell>
                      <TableCell sx={{ color: getColorByValue(parseFloat(position.achievedProfits || 0)) }}>
                        {formatCurrency(position.achievedProfits, position.marginCoin)}
                      </TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatCurrency(position.openPriceAvg, position.marginCoin)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>
                        <Chip
                          label={getMarginModeText(position.marginMode)}
                          size="small"
                          variant="outlined"
                          sx={{ color: 'white', borderColor: 'white' }}
                        />
                      </TableCell>
                      <TableCell sx={{ color: 'white' }}>
                        <Chip
                          label={getPosModeText(position.posMode)}
                          size="small"
                          variant="outlined"
                          sx={{ color: 'white', borderColor: 'white' }}
                        />
                      </TableCell>
                      <TableCell sx={{ color: getColorByValue(parseFloat(position.unrealizedPL || 0)) }}>
                        {formatCurrency(position.unrealizedPL, position.marginCoin)}
                      </TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatCurrency(position.liquidationPrice, position.marginCoin)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatPercentage(parseFloat(position.keepMarginRate || 0) * 100)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatCurrency(position.markPrice, position.marginCoin)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatCurrency(position.breakEvenPrice, position.marginCoin)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatCurrency(position.totalFee, position.marginCoin)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatCurrency(position.deductedFee, position.marginCoin)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.takeProfit || '-'}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.stopLoss || '-'}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.takeProfitId || '-'}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.stopLossId || '-'}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatPercentage(parseFloat(position.marginRatio || 0) * 100)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{position.assetMode || '-'}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatDate(position.cTime)}</TableCell>
                      <TableCell sx={{ color: 'white' }}>{formatDate(position.uTime)}</TableCell>
                    </TableRow>
                  ))
                )}
              </TableBody>
            </Table>
          </TableContainer>
        )}
      </DialogContent>
    </Dialog>
  );
};

export default FinishedOperationsModal;
